def search_chroma(
    query_embedding: list[float],
    tenant_id: str,
    top_k: int = 10,
) -> list[dict]:
    results = collection.query(
        query_embeddings=[query_embedding],
        n_results=top_k,
        where={"tenant_id": {"$eq": tenant_id}},
        include=["documents", "metadatas", "distances"],
    )
    return [
        {
            "content":    results["documents"][0][i],
            "metadata":   results["metadatas"][0][i],
            "similarity": 1 - results["distances"][0][i],  # cosine distance → similarity
        }
        for i in range(len(results["ids"][0]))
    ]

from qdrant_client import QdrantClient
from qdrant_client.models import (
    Distance, VectorParams, PointStruct, Filter, FieldCondition, MatchValue
)

client = QdrantClient(url="http://localhost:6333")

COLLECTION = "chunks"
DIM = 1536

def ensure_collection() -> None:
    existing = [c.name for c in client.get_collections().collections]
    if COLLECTION not in existing:
        client.create_collection(
            collection_name=COLLECTION,
            vectors_config=VectorParams(size=DIM, distance=Distance.COSINE),
        )

def upsert_chunks_qdrant(
    ids: list[int],
    embeddings: list[list[float]],
    payloads: list[dict],
) -> None:
    points = [
        PointStruct(id=ids[i], vector=embeddings[i], payload=payloads[i])
        for i in range(len(ids))
    ]
    client.upsert(collection_name=COLLECTION, points=points)

def upsert_chunks_milvus(tenant_ids, contents, embeddings):
    col.insert([tenant_ids, contents, embeddings])
    col.flush()

def search_milvus(query_embedding, tenant_id, top_k=10):
    results = col.search(
        data=[query_embedding],
        anns_field="embedding",
        param={"metric_type": "COSINE", "params": {"ef": 128}},
        limit=top_k,
        expr=f'tenant_id == "{tenant_id}"',
        output_fields=["content", "tenant_id"],
    )
    return [
        {"content": hit.entity.get("content"), "score": hit.score}
        for hit in results[0]
    ]
